#!/bin/sh
set -eu

if [ ! -d /mnt/us ]; then
    echo "Kindle user storage /mnt/us not found"
    exit 1
fi

cat > /mnt/us/documents/ZenReader.sh <<'EOF'
#!/bin/sh
# Name: Zen Reader
# Author: Zen Labs
# Icon: data:image/png;base64,
# DontUseFBInk
/mnt/us/koreader/koreader.sh --kual --no-framework
EOF

chmod +x /mnt/us/documents/koreader.sh

echo "KOReader Kindle placeholder install complete"
